-- Schema for Domain: seller | Business: Ecommerce | Version: v1_mvm
-- Generated on: 2026-05-05 00:58:27

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `ecommerce_ecm`.`seller` COMMENT 'SSOT for marketplace seller and third-party merchant entities. Owns seller onboarding, KYC/KYB verification, seller profiles, performance scorecards (BSR, DSR), commission structures, GMV attribution, seller tier management, seller agreements, seller ratings, and policy compliance monitoring via the Seller Management Portal.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`seller_profile` (
    `seller_profile_id` BIGINT COMMENT 'Unique identifier for the seller profile record.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Required for internal cost allocation reports that map each sellers expenses to a finance cost center for profitability analysis.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Maps sellers to the legal entity under which they operate, needed for tax filings, regulatory reporting, and jurisdictional compliance.',
    `merchant_account_id` BIGINT COMMENT 'Foreign key linking to payment.merchant_account. Business justification: REQUIRED: Mapping sellers to their merchant accounts enables accurate payout processing, settlement reconciliation, and regulatory reporting.',
    `price_list_id` BIGINT COMMENT 'Foreign key linking to pricing.price_list. Business justification: Each seller profile is assigned a default price list governing their product pricing on the platform. Seller onboarding, pricing operations, and commission calculations all reference the sellers assi',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Enables revenue and margin reporting by assigning each seller to a profit center, a standard practice for financial performance dashboards.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to seller.tier. Business justification: Seller tier classification is defined in the tier reference table; replacing the string tier attribute with a foreign key enforces referential integrity and supports tier‑based analytics.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier. Business justification: In hybrid e-commerce platforms (marketplace + wholesale), a seller is often also a registered procurement supplier. This FK enables unified vendor health reporting, drop-ship eligibility checks, and K',
    `account_status` STRING COMMENT 'Operational status of the sellers marketplace account.. Valid values are `active|suspended|terminated|pending`',
    `business_type` STRING COMMENT 'Classification of the seller based on size and structure.. Valid values are `individual|smb|enterprise`',
    `commission_rate` DECIMAL(18,2) COMMENT 'Percentage of each sale that the marketplace retains as commission from this seller.',
    `compliance_flags` STRING COMMENT 'Pipe‑separated list of compliance indicators (e.g., policy_violations, sanctions).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the seller profile record was first created in the system.',
    `gmv_attribution` DECIMAL(18,2) COMMENT 'Total GMV generated by the seller that is attributed to the marketplace.',
    `incorporation_country` STRING COMMENT 'Three‑letter ISO country code where the seller is legally incorporated.',
    `kyc_completed_date` DATE COMMENT 'Date when KYC verification was successfully completed.',
    `kyc_status` STRING COMMENT 'Current status of Know‑Your‑Customer / Know‑Your‑Business verification.. Valid values are `not_started|in_progress|completed|failed`',
    `legal_name` STRING COMMENT 'Full legal name of the seller entity as registered.',
    `notification_preferences` STRING COMMENT 'Serialized preferences indicating which notification channels the seller opts into (e.g., email, SMS, in‑app).',
    `onboarding_status` STRING COMMENT 'Current state of the seller onboarding workflow.. Valid values are `pending|completed|rejected`',
    `performance_score_bsr` STRING COMMENT 'Numeric score derived from the sellers Best Seller Rank performance.',
    `performance_score_dsr` STRING COMMENT 'Numeric score reflecting the sellers daily sales rate performance.',
    `platform_join_date` DATE COMMENT 'Date the seller first joined the marketplace platform.',
    `preferred_language` STRING COMMENT 'Language the seller prefers for communications and UI.. Valid values are `en|es|fr|de|zh|ja`',
    `primary_category` STRING COMMENT 'Top‑level product category the seller primarily operates in.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary contact.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary point‑of‑contact for the seller.',
    `primary_contact_phone` STRING COMMENT 'Phone number of the primary contact.',
    `registration_number` STRING COMMENT 'Government‑issued registration identifier for the seller (e.g., company registration, business license).',
    `seller_rating` DECIMAL(18,2) COMMENT 'Overall rating score (0‑5) based on buyer feedback and performance metrics.',
    `tax_identifier` STRING COMMENT 'Tax identifier applicable to the seller (VAT, EIN, GST, etc.).',
    `trading_name` STRING COMMENT 'Public-facing name used by the seller on the marketplace.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the seller profile record.',
    CONSTRAINT pk_seller_profile PRIMARY KEY(`seller_profile_id`)
) COMMENT 'Master record for every third-party merchant and marketplace seller entity on the platform. Stores legal business name, trading name, registration number, business type (individual/SMB/enterprise), incorporation country, tax identification numbers (VAT/EIN/GST), primary and secondary contact details (owner name, email, phone, role, notification preferences), primary category, current seller tier reference, onboarding status, account status (active/suspended/terminated), platform join date, and preferred communication language. This is the SSOT for seller identity and contact information — all other seller domain entities reference this record. Sourced from the Seller Management Portal.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`verification` (
    `verification_id` BIGINT COMMENT 'Primary key for verification',
    `onboarding_id` BIGINT COMMENT 'Foreign key linking to seller.onboarding. Business justification: KYC/KYB verification workflows are initiated as part of the seller onboarding process. Linking verification.onboarding_id → onboarding.onboarding_id captures which onboarding workflow triggered each v',
    `seller_profile_id` BIGINT COMMENT 'Unique identifier of the seller to which this verification belongs.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to seller.tier. Business justification: The verification table has a denormalized seller_tier STRING column capturing the sellers tier at the time of verification (used for risk classification and compliance thresholds). The tier table is ',
    `audit_trail_notes` STRING COMMENT 'Additional audit information captured during verification lifecycle.',
    `compliance_status` STRING COMMENT 'Indicates whether the seller meets all required compliance standards.. Valid values are `compliant|non_compliant`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the verification record was first created in the system.',
    `currency_code` STRING COMMENT 'Three‑letter ISO 4217 code of the currency used for monetary values.',
    `document_expiry_timestamp` TIMESTAMP COMMENT 'Date and time when the document expires or becomes invalid.',
    `document_name` STRING COMMENT 'Original file name of the uploaded document.',
    `document_type` STRING COMMENT 'Category of the supporting document submitted. [ENUM-REF-CANDIDATE: passport|business_license|utility_bill|tax_certificate|insurance_certificate|bank_statement|product_certification — 7 candidates stripped; promote to reference product]',
    `document_upload_timestamp` TIMESTAMP COMMENT 'Date and time the document was uploaded to the system.',
    `document_uri` STRING COMMENT 'S3 or blob storage reference where the document is stored.',
    `document_verification_status` STRING COMMENT 'Result of the document verification process.. Valid values are `unverified|verified|expired|rejected`',
    `effective_date` DATE COMMENT 'Date from which the verification is considered active.',
    `expiry_date` DATE COMMENT 'Date after which the verification is no longer valid and must be renewed.',
    `is_platform_issued` BOOLEAN COMMENT 'Indicates whether the document was supplied by the platform rather than the seller.',
    `issuing_authority` STRING COMMENT 'Entity that issued the document (e.g., government agency, bank).',
    `officer_notes` STRING COMMENT 'Free‑form notes entered by the compliance officer reviewing the verification.',
    `provider` STRING COMMENT 'External service or internal team that performed the verification.. Valid values are `Jumio|Onfido|Trulioo|Manual`',
    `rejection_reason_code` STRING COMMENT 'Standardized code indicating why a verification was rejected.',
    `risk_classification` STRING COMMENT 'Risk level assigned to the seller based on verification outcomes.. Valid values are `low|medium|high|critical`',
    `seller_gmv_at_verification` DECIMAL(18,2) COMMENT 'Total GMV attributed to the seller at the time of verification.',
    `submission_timestamp` TIMESTAMP COMMENT 'Date and time when the seller submitted verification materials.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the verification record.',
    `verification_type` STRING COMMENT 'Category of verification performed (e.g., identity, business, bank, tax).. Valid values are `identity|business|bank|tax`',
    `workflow_status` STRING COMMENT 'Current state of the verification workflow.. Valid values are `pending|in_review|approved|rejected|expired`',
    CONSTRAINT pk_verification PRIMARY KEY(`verification_id`)
) COMMENT 'Tracks Know Your Customer / Know Your Business (KYC/KYB) identity verification workflows and serves as the authoritative document repository for all seller-submitted compliance materials. Captures verification type (identity/business/bank/tax), verification provider, submission date, workflow status (pending/in_review/approved/rejected/expired), rejection reason codes, risk classification, and compliance officer notes. Stores associated documents: document type (passport/business_license/utility_bill/tax_certificate/insurance_certificate/bank_statement/product_certification), document name, file reference (S3/blob URI), upload date, expiry date, issuing authority, document verification status (unverified/verified/expired/rejected), and whether document is seller-submitted or platform-issued. Each seller may have multiple verification records with multiple associated documents across lifecycle events. Supports regulatory obligations under FTC, GDPR, AML/CFT, CPSC, and EU DAC7 frameworks. Single point of response for regulatory document requests and KYC audit inquiries.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`onboarding` (
    `onboarding_id` BIGINT COMMENT 'Primary key for onboarding',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: In marketplace e-commerce, a customer applies to become a seller via their existing customer account. Linking onboarding to the originating customer account enables KYC cross-referencing, identity ver',
    `agent_id` BIGINT COMMENT 'Identifier of the internal reviewer responsible for evaluating the onboarding application.',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: Seller onboarding is marketplace-specific — compliance requirements, category approvals, and go-live processes differ per marketplace. Onboarding operations teams track pipeline by marketplace; withou',
    `seller_profile_id` BIGINT COMMENT 'Unique identifier of the seller (party) applying for marketplace participation.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier. Business justification: Dual-track onboarding (marketplace seller + procurement supplier) is a real operational process in hybrid e-commerce. Linking the seller onboarding record to the procurement supplier record allows onb',
    `tier_id` BIGINT COMMENT 'Foreign key linking to seller.tier. Business justification: The onboarding table has a denormalized seller_tier STRING column capturing the tier classification assigned or requested during onboarding. The tier table is the authoritative reference master. Addin',
    `agreement_signed_date` DATE COMMENT 'Date on which the seller signed the marketplace participation agreement.',
    `agreement_version` STRING COMMENT 'Version identifier of the seller agreement that was signed.',
    `application_number` STRING COMMENT 'Human‑readable identifier assigned to the onboarding application for tracking and reference.',
    `business_model` STRING COMMENT 'Classification of the sellers commercial model (Business‑to‑Consumer, Business‑to‑Business, Consumer‑to‑Consumer).. Valid values are `B2C|B2B|C2C`',
    `category_requested` STRING COMMENT 'Primary product category the seller wishes to list on the marketplace.',
    `compliance_check_passed` BOOLEAN COMMENT 'Result of automated compliance checks (e.g., KYC/KYB) – True if all checks passed.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this onboarding record was first created in the system.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether the application has been escalated for senior review (True) or not (False).',
    `estimated_commission_amount` DECIMAL(18,2) COMMENT 'Projected commission the marketplace will retain from the sellers GMV, based on the agreed commission structure.',
    `estimated_gmv_amount` DECIMAL(18,2) COMMENT 'Projected gross merchandise value the seller is expected to generate after onboarding, expressed in the transaction currency.',
    `estimated_gmv_currency` STRING COMMENT 'Three‑letter ISO 4217 currency code for the estimated GMV amount.. Valid values are `^[A-Z]{3}$`',
    `fulfillment_model` STRING COMMENT 'Method the seller uses to fulfill orders: Fulfilled by platform (FBA‑style), self‑fulfilled, or third‑party logistics (3PL).. Valid values are `fba_style|self_fulfilled|3pl`',
    `go_live_date` DATE COMMENT 'Planned date when the seller becomes active on the marketplace after successful onboarding.',
    `net_estimated_gmv_amount` DECIMAL(18,2) COMMENT 'Estimated GMV after subtracting the marketplace commission; represents the sellers net revenue expectation.',
    `onboarding_status` STRING COMMENT 'Current lifecycle state of the onboarding application. Values represent the sequential stages from submission to live or rejection. [ENUM-REF-CANDIDATE: applied|document_review|kyc_check|category_approval|agreement_signed|live|rejected — 7 candidates stripped; promote to reference product]',
    `rejection_reason` STRING COMMENT 'Free‑text explanation provided when an application is rejected.',
    `seller_contact_email` STRING COMMENT 'Primary email address for communication with the seller during onboarding.',
    `seller_contact_phone` STRING COMMENT 'Primary phone number for contacting the seller during onboarding.',
    `seller_rating` DECIMAL(18,2) COMMENT 'Numeric rating (0.00‑5.00) reflecting seller performance metrics such as order defect rate and customer feedback.',
    `submission_timestamp` TIMESTAMP COMMENT 'Exact date‑time when the seller submitted the onboarding application.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the onboarding record.',
    CONSTRAINT pk_onboarding PRIMARY KEY(`onboarding_id`)
) COMMENT 'Captures the end-to-end seller onboarding workflow record initiated when a merchant applies to join the marketplace. Tracks application submission date, onboarding stage (applied/document_review/kyc_check/category_approval/agreement_signed/live), assigned reviewer, category requested, business model (B2C/B2B/C2C), fulfillment model (FBA-style/self-fulfilled/3PL), estimated GMV, rejection reasons, escalation flags, and go-live date. Sourced from the Seller Management Portal onboarding module.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`agreement` (
    `agreement_id` BIGINT COMMENT 'Unique system-generated identifier for each seller agreement record.',
    `commission_id` BIGINT COMMENT 'Foreign key linking to seller.commission. Business justification: The seller_agreement contains commission_rate (DECIMAL) and commission_structure_code (STRING) which are denormalized copies of data owned by the commission table (rate_percent and commission_code res',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Seller agreements are executed under a specific legal entity (jurisdiction field exists on seller_agreement). The contracting legal entity determines which entitys books record the agreement obligati',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: Seller agreements are marketplace-specific contracts — terms of service, commission rates, and SLA commitments differ per marketplace. Legal and compliance teams must query active agreements by market',
    `onboarding_id` BIGINT COMMENT 'Foreign key linking to seller.onboarding. Business justification: A seller_agreement is the contractual output of the onboarding workflow. Linking seller_agreement.onboarding_id → onboarding.onboarding_id captures which onboarding process produced this agreement, en',
    `price_list_id` BIGINT COMMENT 'Foreign key linking to pricing.price_list. Business justification: Seller agreements contractually reference the price list governing the sellers pricing terms during the agreement period. Contract management and compliance audits require tracing which price list wa',
    `seller_profile_id` BIGINT COMMENT 'Unique identifier of the seller to which this agreement applies.',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to service.sla_policy. Business justification: Seller agreements contractually bind sellers to specific SLA policies governing response times, fulfillment standards, and dispute resolution. Contract management and compliance enforcement teams requ',
    `agreement_number` STRING COMMENT 'External business identifier or contract number assigned to the agreement.',
    `agreement_type` STRING COMMENT 'Classification of the agreement (e.g., standard, enterprise, category‑specific).. Valid values are `standard|enterprise|category_specific`',
    `amendment_date` DATE COMMENT 'Date of the most recent amendment to the agreement.',
    `compliance_status` STRING COMMENT 'Current compliance standing of the seller with marketplace policies and regulations.. Valid values are `compliant|non_compliant|under_review`',
    `confidentiality_clause` STRING COMMENT 'Text of the confidentiality obligations imposed on the seller.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the agreement record was first created in the system.',
    `currency_code` STRING COMMENT 'Three‑letter ISO 4217 code of the currency used for monetary fields.',
    `data_retention_period_days` STRING COMMENT 'Number of days the agreement data must be retained for regulatory purposes.',
    `digital_signature_timestamp` TIMESTAMP COMMENT 'Timestamp when the agreement was digitally signed by the parties.',
    `dispute_resolution_mechanism` STRING COMMENT 'Procedures and jurisdiction for resolving disputes under the agreement.',
    `early_termination_fee` DECIMAL(18,2) COMMENT 'Fee charged to the seller for terminating the agreement before the effective end date.',
    `effective_end_date` DATE COMMENT 'Date when the agreement expires or terminates; null for open‑ended contracts.',
    `effective_start_date` DATE COMMENT 'Date when the agreement becomes binding.',
    `gmv_attribution` DECIMAL(18,2) COMMENT 'Total GMV amount attributed to the seller under this agreement.',
    `intellectual_property_terms` STRING COMMENT 'Terms governing IP ownership, licensing, and usage of seller‑provided content.',
    `jurisdiction` STRING COMMENT 'ISO 3166‑1 alpha‑3 country code of the legal jurisdiction governing the agreement.',
    `max_order_volume` STRING COMMENT 'Maximum number of orders the seller may process per defined period under this agreement.',
    `max_sku_count` STRING COMMENT 'Maximum distinct SKUs the seller is permitted to list under this agreement.',
    `notice_period_days` STRING COMMENT 'Required notice period (in days) for termination or amendment.',
    `performance_score` DECIMAL(18,2) COMMENT 'Composite score reflecting seller performance metrics (e.g., CSAT, DSR, BSR).',
    `prohibited_category_clauses` STRING COMMENT 'List of product categories the seller is prohibited from listing under this agreement.',
    `renewal_date` DATE COMMENT 'Scheduled date for automatic renewal or review of the agreement.',
    `return_policy_terms` STRING COMMENT 'Textual description of the return and refund policy applicable to the seller.',
    `seller_agreement_status` STRING COMMENT 'Current lifecycle status of the agreement.. Valid values are `draft|active|suspended|terminated|pending`',
    `seller_tier` STRING COMMENT 'Tier classification of the seller based on performance and volume.. Valid values are `bronze|silver|gold|platinum`',
    `termination_conditions` STRING COMMENT 'Conditions under which the agreement may be terminated by either party.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the agreement record.',
    `version_number` STRING COMMENT 'Sequential version number of the agreement document.',
    CONSTRAINT pk_agreement PRIMARY KEY(`agreement_id`)
) COMMENT 'Stores the contractual agreement records between the marketplace platform and each seller. Captures agreement type (standard/enterprise/category-specific), effective date, expiration date, governing jurisdiction, commission rate schedule reference, return policy terms, SLA commitments, prohibited category clauses, intellectual property terms, agreement version, digital signature timestamp, and termination conditions. Tracks amendments and renewals as versioned records. Supports SOX and FTC compliance for marketplace contracts.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`commission` (
    `commission_id` BIGINT COMMENT 'Primary key for commission',
    `general_ledger_id` BIGINT COMMENT 'Foreign key linking to finance.general_ledger. Business justification: Commission rate structures map to specific GL revenue accounts for commission income posting and accrual. Finance teams configure commission-to-GL account mappings for automated posting in ERP-integra',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: Seller commission structures are negotiated per marketplace — a seller may have different referral fee rates on different marketplaces. Commission reporting, fee disclosure, and rate card audits are a',
    `seller_profile_id` BIGINT COMMENT 'Identifier of the seller to which this commission structure applies.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to seller.tier. Business justification: The commission table has a denormalized seller_tier STRING column that references the tier classification. The tier table is the authoritative reference master for seller tier definitions. Adding comm',
    `cap_amount` DECIMAL(18,2) COMMENT 'Maximum commission amount that can be charged per transaction.',
    `commission_code` STRING COMMENT 'External reference code for the commission structure used in contracts and reporting.',
    `commission_description` STRING COMMENT 'Narrative description of the commission structure and its purpose.',
    `commission_status` STRING COMMENT 'Current lifecycle status of the commission structure.. Valid values are `active|inactive|pending|suspended|terminated|draft`',
    `commission_type` STRING COMMENT 'Classification of the commission structure (e.g., standard, negotiated, tiered, category-specific override).. Valid values are `standard|negotiated|tiered|category_override`',
    `currency_code` STRING COMMENT 'Three-letter ISO currency code for monetary values.. Valid values are `^[A-Z]{3}$`',
    `effective_from` DATE COMMENT 'Date when the commission structure becomes effective.',
    `effective_until` DATE COMMENT 'Date when the commission structure expires; null if open-ended.',
    `fulfillment_fee_rate_percent` DECIMAL(18,2) COMMENT 'Fee percentage for fulfillment services (e.g., FBA-style).',
    `is_negotiated` BOOLEAN COMMENT 'Indicates whether the commission structure is individually negotiated.',
    `minimum_commission_amount` DECIMAL(18,2) COMMENT 'Floor amount ensuring minimum commission per transaction.',
    `product_category_code` STRING COMMENT 'Code representing the product category for which the commission rate applies.',
    `promotional_coop_fee_percent` DECIMAL(18,2) COMMENT 'Commission percentage for promotional co-op fees.',
    `rate_percent` DECIMAL(18,2) COMMENT 'Base commission percentage applied to the sellers gross merchandise value.',
    `record_audit_created` TIMESTAMP COMMENT 'Timestamp when the commission record was initially created.',
    `record_audit_updated` TIMESTAMP COMMENT 'Timestamp of the most recent update to the commission record.',
    `referral_fee_percent` DECIMAL(18,2) COMMENT 'Additional referral fee percentage applied per transaction.',
    `subscription_fee_amount` DECIMAL(18,2) COMMENT 'Fixed periodic subscription fee for the seller tier.',
    `tax_applicable` BOOLEAN COMMENT 'Indicates if tax is applied to commission fees.',
    `variable_closing_fee_amount` DECIMAL(18,2) COMMENT 'Variable fee charged per transaction based on closing costs.',
    `version` STRING COMMENT 'Version number of the commission structure for change tracking.',
    CONSTRAINT pk_commission PRIMARY KEY(`commission_id`)
) COMMENT 'Defines the commission and fee schedule applicable to a seller or seller tier. Captures commission rate by product category, referral fee percentage, variable closing fee, subscription fee tier, FBA-style fulfillment fee rates, promotional co-op fee, minimum commission floor, effective date range, and whether the structure is negotiated (enterprise) or standard. Supports GMV-based tiered commission models and category-specific rate overrides. Referenced by payment settlement and GMV attribution processes.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`scorecard` (
    `scorecard_id` BIGINT COMMENT 'Primary key for scorecard',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: Seller performance scorecards are marketplace-specific — ODR, late shipment rate, and DSR thresholds differ per marketplace and a sellers tier eligibility is evaluated per marketplace. Without this F',
    `seller_profile_id` BIGINT COMMENT 'Identifier of the seller to which this scorecard belongs.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to seller.tier. Business justification: The scorecard captures the sellers tier standing during each performance period. The performance_tier_rating STRING column is a denormalized reference to the tier classification. Adding scorecard.tie',
    `aov` DECIMAL(18,2) COMMENT 'Average monetary value per order for the seller.',
    `bsr` STRING COMMENT 'Sellers rank within its product category based on sales performance.',
    `cancellation_rate` DECIMAL(18,2) COMMENT 'Proportion of orders cancelled by the seller or buyer during the period.',
    `commission_rate` DECIMAL(18,2) COMMENT 'Percentage of seller sales retained as platform commission.',
    `conversion_rate` DECIMAL(18,2) COMMENT 'Ratio of seller listing views that resulted in a purchase.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the scorecard record was initially created.',
    `customer_complaint_count` STRING COMMENT 'Number of complaints logged against the seller during the period.',
    `dsr` DECIMAL(18,2) COMMENT 'Total sales amount generated by the seller per day within the period.',
    `gmv` DECIMAL(18,2) COMMENT 'Total monetary value of goods sold by the seller in the period.',
    `inventory_health_score` DECIMAL(18,2) COMMENT 'Composite score reflecting inventory availability and turnover for the seller.',
    `last_tier_change_date` DATE COMMENT 'Date when the seller most recently moved to a new performance tier.',
    `late_shipment_rate` DECIMAL(18,2) COMMENT 'Percentage of shipments dispatched later than the promised delivery window.',
    `notes` STRING COMMENT 'Free‑form comments or observations added by the performance monitoring team.',
    `nps_contribution_score` DECIMAL(18,2) COMMENT 'Sellers contribution to the Net Promoter Score based on customer feedback.',
    `order_defect_rate` DECIMAL(18,2) COMMENT 'Proportion of orders with defects (e.g., cancellations, returns) expressed as a decimal fraction.',
    `period_end_date` DATE COMMENT 'Last calendar date of the scorecard reporting period.',
    `period_start_date` DATE COMMENT 'First calendar date of the scorecard reporting period.',
    `period_type` STRING COMMENT 'Granularity of the reporting period (daily, weekly, or monthly).. Valid values are `daily|weekly|monthly`',
    `policy_violation_count` STRING COMMENT 'Count of compliance policy breaches recorded for the seller.',
    `return_rate` DECIMAL(18,2) COMMENT 'Fraction of sold items that were returned by customers.',
    `suspension_flag` BOOLEAN COMMENT 'True if the seller was suspended at any point in the period.',
    `tier_change_flag` BOOLEAN COMMENT 'Indicates whether the sellers tier changed during the period.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the scorecard record.',
    CONSTRAINT pk_scorecard PRIMARY KEY(`scorecard_id`)
) COMMENT 'Periodic performance scorecard record for each seller capturing key operational and commercial KPIs used for tier management and enforcement decisions. Stores scorecard period (daily/weekly/monthly), DSR (Daily Sales Rate), BSR (Best Seller Rank) within category, order defect rate (ODR), late shipment rate, cancellation rate, return rate, NPS contribution score, customer complaint count, policy violation count, GMV for period, AOV (Average Order Value), conversion rate on seller listings, inventory health score, and overall performance tier rating. Used for automated tier promotion/demotion triggers, suspension threshold monitoring, and incentive program eligibility. Sourced from Seller Management Portal performance monitoring module.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`gmv_settlement` (
    `gmv_settlement_id` BIGINT COMMENT 'Primary key for gmv_settlement',
    `accounts_receivable_id` BIGINT COMMENT 'Foreign key linking to finance.accounts_receivable. Business justification: Seller GMV settlements clear outstanding AR balances in the marketplace facilitator model. Finance AR aging, cash application, and settlement reconciliation processes require linking each settlement t',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to seller.seller_agreement. Business justification: Each GMV settlement is processed under the terms of a specific seller agreement (which governs commission rates, SLA commitments, currency, and payout terms). Linking gmv_settlement.seller_agreement_i',
    `commission_id` BIGINT COMMENT 'Foreign key linking to seller.commission. Business justification: Each GMV settlement applies a specific commission schedule to calculate the commission_amount deducted. Linking gmv_settlement.commission_id → commission.commission_id captures which commission rate/f',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Seller GMV settlements generate journal entries for commission revenue, payout disbursements, and tax liabilities. Finance period-end close and GL reconciliation processes require tracing each settlem',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: GMV settlements are marketplace-scoped — a seller operating on multiple marketplaces (e.g., Amazon US, Amazon EU) has separate settlement cycles per marketplace. Without marketplace_id, cross-marketpl',
    `seller_settlement_id` BIGINT COMMENT 'Foreign key linking to marketplace.seller_settlement. Business justification: Finance reconciliation requires matching seller-domain GMV settlement records to marketplace-domain disbursement records. These represent the same business event from two ledger perspectives; without ',
    `promotional_campaign_id` BIGINT COMMENT 'Foreign key linking to pricing.promotional_campaign. Business justification: GMV settlements include promotional_subsidy_amount funded by specific campaigns. Linking to promotional_campaign enables campaign ROI reporting, P&L attribution of subsidies, and finance reconciliatio',
    `seller_bank_account_id` BIGINT COMMENT 'Foreign key linking to seller.seller_bank_account. Business justification: Each GMV settlement results in a payout disbursed to a specific seller bank account. Linking gmv_settlement.seller_bank_account_id → seller_bank_account.seller_bank_account_id captures exactly which v',
    `seller_profile_id` BIGINT COMMENT 'Identifier of the seller to whom this GMV settlement applies.',
    `settlement_id` BIGINT COMMENT 'Foreign key linking to payment.settlement. Business justification: Seller GMV payouts must be reconciled against the platforms acquiring-bank settlement batches. Finance audit trails require tracing which payment settlement batch funded each seller disbursement. Thi',
    `business_event_timestamp` TIMESTAMP COMMENT 'Timestamp of the settlement processing event.',
    `channel` STRING COMMENT 'Origin channel of the sales contributing to this GMV.. Valid values are `web|mobile|api`',
    `commission_amount` DECIMAL(18,2) COMMENT 'Platform commission charged on the net GMV.',
    `compliance_flag` BOOLEAN COMMENT 'Indicates whether the settlement passed all compliance checks.',
    `currency_code` STRING COMMENT 'Three-letter ISO currency code for monetary amounts.. Valid values are `^[A-Z]{3}$`',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Exchange rate applied to convert foreign currency to base reporting currency.',
    `gmv_source` STRING COMMENT 'Source channel of GMV attribution.. Valid values are `marketplace|seller_direct|partner`',
    `gross_gmv_amount` DECIMAL(18,2) COMMENT 'Total gross sales amount before deductions for the period.',
    `net_gmv_amount` DECIMAL(18,2) COMMENT 'Net GMV after returns, representing amount payable to seller before commissions.',
    `notes` STRING COMMENT 'Free-text notes or comments regarding the settlement.',
    `payout_amount` DECIMAL(18,2) COMMENT 'Final payout amount transferred to seller after all deductions.',
    `payout_date` DATE COMMENT 'Date on which payout was transferred to the sellers bank account.',
    `payout_method` STRING COMMENT 'Method used to transfer payout to seller.. Valid values are `bank_transfer|paypal|check`',
    `period_end_date` DATE COMMENT 'End date of the attribution period covered by this settlement.',
    `period_start_date` DATE COMMENT 'Start date of the attribution period covered by this settlement.',
    `promotional_subsidy_amount` DECIMAL(18,2) COMMENT 'Total promotional subsidies applied to the sellers sales.',
    `record_audit_created` TIMESTAMP COMMENT 'Timestamp when the settlement record was first created in the system.',
    `record_audit_updated` TIMESTAMP COMMENT 'Timestamp of the most recent update to the settlement record.',
    `returns_amount` DECIMAL(18,2) COMMENT 'Total amount of returns and refunds deducted from gross GMV.',
    `settlement_date` DATE COMMENT 'Date on which the settlement was executed.',
    `settlement_status` STRING COMMENT 'Current processing status of the settlement.. Valid values are `pending|processed|failed|reconciled`',
    `settlement_type` STRING COMMENT 'Indicates whether the settlement is routine periodic or ad-hoc adjustment.. Valid values are `periodic|ad_hoc`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Tax collected on behalf of the seller for the period.',
    CONSTRAINT pk_gmv_settlement PRIMARY KEY(`gmv_settlement_id`)
) COMMENT 'Transactional record attributing Gross Merchandise Value (GMV) to individual sellers for each settlement period. Captures gross sales amount, returns and refunds deducted, net GMV, platform commission charged, promotional subsidy applied, tax collected on behalf of seller, currency, exchange rate, attribution period start/end dates, and GMV source channel (web/mobile/API). Supports financial reporting, seller tier evaluation, and marketplace revenue recognition. Links to order and payment domains for reconciliation.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`rating` (
    `rating_id` BIGINT COMMENT 'Primary key for rating',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: Seller ratings are marketplace-specific — a sellers reputation score on one marketplace is independent of another. Marketplace trust and safety teams moderate ratings per marketplace; buy-box eligibi',
    `seller_profile_id` BIGINT COMMENT 'Foreign key linking to seller.seller_profile. Business justification: Rating records need to be associated with the seller being reviewed; adding seller_profile_id enables this relationship and removes the need for any redundant seller fields (none exist).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the rating record was first created in the system.',
    `dimension_communication` STRING COMMENT 'Buyer’s rating of the seller’s communication quality.',
    `dimension_item_as_described` STRING COMMENT 'Buyer’s rating of how accurately the item matched its description.',
    `dimension_packaging` STRING COMMENT 'Buyer’s rating of the quality of the item’s packaging.',
    `dimension_shipping_speed` STRING COMMENT 'Buyer’s rating of how quickly the seller shipped the item.',
    `helpful_votes` STRING COMMENT 'Number of other buyers who marked the review as helpful.',
    `language` STRING COMMENT 'ISO 639‑1 code of the language used in the review text.',
    `moderation_status` STRING COMMENT 'Current moderation state of the review: pending, approved, or removed.. Valid values are `pending|approved|removed`',
    `order_reference` BIGINT COMMENT 'Identifier of the order associated with the rating, linking the purchase to the review.',
    `rating_source` STRING COMMENT 'Channel through which the rating was submitted: website, mobile app, or API.. Valid values are `website|mobile_app|api`',
    `removal_reason` STRING COMMENT 'Reason provided by moderation team when a review is removed.',
    `review_date` TIMESTAMP COMMENT 'Timestamp when the buyer submitted the rating.',
    `review_text` STRING COMMENT 'Free‑form textual feedback provided by the buyer.',
    `score` STRING COMMENT 'Overall rating given by the buyer on a scale of 1 (lowest) to 5 (highest).',
    `seller_response_date` TIMESTAMP COMMENT 'Timestamp when the seller posted a response to the review.',
    `seller_response_text` STRING COMMENT 'Text of the seller’s response to the buyer’s review, if any.',
    `unhelpful_votes` STRING COMMENT 'Number of other buyers who marked the review as unhelpful.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the rating record.',
    `verified_purchase` BOOLEAN COMMENT 'Indicates whether the rating is tied to a completed purchase (True) or not (False).',
    CONSTRAINT pk_rating PRIMARY KEY(`rating_id`)
) COMMENT 'Stores buyer-submitted ratings and reviews for individual sellers. Captures rating score (1-5), review text, review date, order reference, verified purchase flag, rating dimensions (communication/shipping_speed/item_as_described/packaging), seller response text, seller response date, moderation status (pending/approved/removed), removal reason, and helpfulness votes. Aggregated ratings feed into seller scorecard and tier management. Supports NPS and CSAT tracking at the seller level.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`violation` (
    `violation_id` BIGINT COMMENT 'Primary key for violation',
    `accounts_receivable_id` BIGINT COMMENT 'Foreign key linking to finance.accounts_receivable. Business justification: Seller violations with fines (fine_amount field) generate AR records — the platform has a receivable from the seller for the fine. Finance AR collections and dunning processes for seller fines require',
    `agent_id` BIGINT COMMENT 'Internal identifier of the compliance investigator handling the case.',
    `marketplace_id` BIGINT COMMENT 'Foreign key linking to marketplace.marketplace. Business justification: Policy violations are enforced per marketplace — a suspension on Amazon US does not automatically apply to Amazon EU. Marketplace compliance teams run violation reports scoped to their marketplace; wi',
    `support_case_id` BIGINT COMMENT 'Foreign key linking to service.service_support_case. Business justification: Compliance audit and violation investigation workflows require tracing each seller violation back to the originating support case (e.g., buyer complaint triggering a policy breach investigation). Regu',
    `seller_profile_id` BIGINT COMMENT 'Unique identifier of the seller to whom the violation applies.',
    `appeal_deadline` DATE COMMENT 'Last date by which the seller can submit an appeal.',
    `appeal_eligibility` BOOLEAN COMMENT 'Indicates whether the seller may appeal the enforcement action.',
    `appeal_outcome` STRING COMMENT 'Result of the sellers appeal, if filed.. Valid values are `upheld|dismissed|reinstated|none`',
    `compliance_region` STRING COMMENT 'Geographic region (ISO 3166‑1 alpha‑3) governing the applicable regulations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the violation record was first created in the system.',
    `currency_code` STRING COMMENT 'Three‑letter ISO 4217 code of the currency for the fine amount.',
    `detection_method` STRING COMMENT 'How the violation was identified: automated rule, manual review, buyer report, or regulatory notice.. Valid values are `automated_rule|manual_review|buyer_report|regulatory_notice`',
    `detection_timestamp` TIMESTAMP COMMENT 'Date and time when the violation was first detected.',
    `enforcement_action` STRING COMMENT 'Action taken against the seller as a result of the violation.. Valid values are `warning_issued|listing_removed|account_suspended|account_terminated|probation_applied`',
    `evidence_reference` STRING COMMENT 'Link (URL or internal ID) to supporting evidence such as screenshots, logs, or documents.',
    `expected_reinstatement_date` DATE COMMENT 'Planned date for lifting the suspension, if applicable.',
    `fine_amount` DECIMAL(18,2) COMMENT 'Monetary penalty assessed for the violation, if any.',
    `investigation_status` STRING COMMENT 'Current state of the investigation workflow.. Valid values are `open|under_review|upheld|dismissed|appealed`',
    `lifecycle_status` STRING COMMENT 'High‑level status of the violation record across its full lifecycle.. Valid values are `detected|investigating|enforced|appealed|resolved|reinstated`',
    `notes` STRING COMMENT 'Additional comments or observations recorded by investigators.',
    `policy_code` STRING COMMENT 'Internal code of the marketplace policy that was breached.',
    `policy_description` STRING COMMENT 'Human‑readable description of the violated policy.',
    `regulatory_body` STRING COMMENT 'Regulatory authority whose rules are implicated by the violation.. Valid values are `FTC|CPSC|PCI_DSS|GDPR|CCPA`',
    `reinstatement_conditions` STRING COMMENT 'Specific requirements the seller must satisfy to have the account reinstated.',
    `seller_gmv_at_violation` DECIMAL(18,2) COMMENT 'Total GMV generated by the seller at the time the violation was recorded.',
    `severity_level` STRING COMMENT 'Business impact rating of the violation, ranging from warning to critical.. Valid values are `warning|minor|major|critical`',
    `suspension_effective_date` DATE COMMENT 'Date when the sellers account suspension becomes active.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the violation record.',
    `violation_number` STRING COMMENT 'Human‑readable reference number for the violation, used in communications and reporting.',
    `violation_type` STRING COMMENT 'Category of policy breach (e.g., counterfeit, prohibited item, pricing manipulation, review fraud, IP infringement, data misuse).. Valid values are `counterfeit|prohibited_item|pricing_manipulation|review_fraud|ip_infringement|data_misuse`',
    CONSTRAINT pk_violation PRIMARY KEY(`violation_id`)
) COMMENT 'Records policy breaches, enforcement actions, and account suspension/reinstatement events for sellers who violate marketplace policies, regulatory requirements, or platform terms of service. Captures violation type (counterfeit/prohibited_item/pricing_manipulation/review_fraud/IP_infringement/data_misuse), detection method (automated_rule/manual_review/buyer_report/regulatory_notice), severity level (warning/minor/major/critical), detection date, evidence references, assigned investigator, investigation status (open/under_review/upheld/dismissed/appealed), enforcement action taken (warning_issued/listing_removed/account_suspended/account_terminated/probation_applied), suspension effective date, expected reinstatement date, appeal eligibility and deadline, appeal outcome, and reinstatement conditions. Provides complete enforcement lifecycle from detection through resolution including suspension/reinstatement audit trail. Supports FTC, CPSC, and platform trust & safety compliance.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`tier` (
    `tier_id` BIGINT COMMENT 'Primary key for tier',
    `agent_id` BIGINT COMMENT 'Foreign key linking to service.agent. Business justification: Required for Tier Management: each seller tier assigns a dedicated account manager (service.agent) to support sellers; reports on manager performance per tier depend on this link.',
    `price_list_id` BIGINT COMMENT 'Foreign key linking to pricing.price_list. Business justification: Seller tiers directly determine which price list applies — Gold/Silver/Bronze tiers receive different pricing terms and fee structures. Tier-based price list assignment is a core e-commerce marketplac',
    `api_rate_priority` BOOLEAN COMMENT 'Flag indicating priority access to API rate limits.',
    `badge_display_eligible` BOOLEAN COMMENT 'Indicates if the tier badge can be displayed on the sellers storefront.',
    `commission_rate_discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount applied to the standard commission rate for sellers in this tier.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the tier record was created.',
    `demotion_grace_period_days` STRING COMMENT 'Number of days after a downgrade trigger before the tier is actually changed.',
    `effective_from` DATE COMMENT 'Date when the tier definition becomes effective.',
    `effective_until` DATE COMMENT 'Date when the tier definition is retired; null if still active.',
    `eligibility_criteria_notes` STRING COMMENT 'Free‑text notes describing any additional eligibility criteria for the tier.',
    `enhanced_analytics_access` BOOLEAN COMMENT 'Flag indicating access to advanced analytics dashboards.',
    `is_default_tier` BOOLEAN COMMENT 'Indicates whether this tier is the default assignment for new sellers.',
    `last_review_timestamp` TIMESTAMP COMMENT 'Timestamp of the last tier review execution.',
    `minimum_gmv_usd` DECIMAL(18,2) COMMENT 'Minimum Gross Merchandise Value in USD a seller must achieve to qualify for this tier.',
    `minimum_scorecard_rating` DECIMAL(18,2) COMMENT 'Minimum average scorecard rating (0‑5) required for tier eligibility.',
    `minimum_tenure_days` STRING COMMENT 'Minimum number of days the seller must have been active on the platform to qualify.',
    `premium_feature_access` BOOLEAN COMMENT 'Indicates whether sellers in this tier have access to premium platform features.',
    `review_cadence` STRING COMMENT 'Frequency at which the sellers tier is reviewed.. Valid values are `monthly|quarterly|annual`',
    `tier_code` STRING COMMENT 'Unique short code identifying the seller tier (e.g., BRZ, SLV, GLD).',
    `tier_description` STRING COMMENT 'Detailed description of the tier, its purpose and benefits.',
    `tier_name` STRING COMMENT 'Human‑readable name of the seller tier such as Bronze, Silver, Gold.',
    `tier_rank` STRING COMMENT 'Ordinal rank of the tier; lower number indicates a higher tier.',
    `tier_status` STRING COMMENT 'Current lifecycle status of the tier.. Valid values are `active|inactive|deprecated`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the tier record.',
    CONSTRAINT pk_tier PRIMARY KEY(`tier_id`)
) COMMENT 'Reference master defining the marketplace seller tier classification hierarchy. Captures tier name (Bronze/Silver/Gold/Platinum/Enterprise), qualification thresholds (minimum GMV, minimum scorecard rating, minimum tenure), benefits granted (commission rate discount percentage, premium feature access flags, dedicated account manager eligibility, API rate priority, enhanced analytics access), badge display eligibility, tier review cadence (monthly/quarterly), demotion grace period rules, and tier-specific SLA commitments. Provides the authoritative classification framework referenced by profile for current tier assignment, by scorecard for promotion/demotion evaluation, and by commission for rate resolution.';

CREATE OR REPLACE TABLE `ecommerce_ecm`.`seller`.`seller_bank_account` (
    `seller_bank_account_id` BIGINT COMMENT 'System-generated unique identifier for the seller bank account record.',
    `finance_bank_account_id` BIGINT COMMENT 'Foreign key linking to finance.finance_bank_account. Business justification: Seller bank accounts receive payouts disbursed from the platforms finance bank accounts. Treasury cash management and payout routing processes track which platform bank account disburses to each sell',
    `seller_profile_id` BIGINT COMMENT 'Foreign key linking to seller.seller_profile. Business justification: Bank account records belong to a seller; linking enables aggregation of payouts, compliance tracking, and eliminates orphan bank account records.',
    `account_holder_name` STRING COMMENT 'Legal name of the individual or organization that owns the bank account.',
    `account_nickname` STRING COMMENT 'User‑defined friendly name for the bank account (e.g., "US‑USD Account").',
    `account_number` STRING COMMENT 'Tokenized or masked bank account number stored in PCI‑DSS compliant vault.',
    `account_type` STRING COMMENT 'Classification of the bank account (e.g., checking, savings, business).. Valid values are `checking|savings|business`',
    `bank_name` STRING COMMENT 'Name of the financial institution where the account is held.',
    `compliance_status` STRING COMMENT 'Indicates whether the account meets PCI‑DSS and regulatory compliance requirements.. Valid values are `compliant|non_compliant|under_review`',
    `country_code` STRING COMMENT 'Three‑letter ISO country code where the bank account is domiciled.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the bank account record was first created in the system.',
    `currency_code` STRING COMMENT 'Three‑letter ISO currency code of the account (e.g., USD, EUR).. Valid values are `^[A-Z]{3}$`',
    `data_retention_period_days` STRING COMMENT 'Number of days the bank account data must be retained per regulatory policy.',
    `date_verified` DATE COMMENT 'Calendar date on which the bank account was successfully verified.',
    `disbursement_limit` DECIMAL(18,2) COMMENT 'Maximum monetary amount that can be disbursed to this account per transaction or period.',
    `disbursement_limit_currency` STRING COMMENT 'Currency of the disbursement limit amount.. Valid values are `^[A-Z]{3}$`',
    `iban` STRING COMMENT 'Standardized international account identifier per ISO 13616.. Valid values are `^[A-Z]{2}[0-9A-Z]{13,34}$`',
    `last_used_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent payout made to this bank account.',
    `primary_payout_flag` BOOLEAN COMMENT 'Indicates whether this account is the default payout method for the seller.',
    `routing_number` STRING COMMENT 'Domestic routing identifier for the bank (e.g., ABA routing number in the US).. Valid values are `^d{9}$`',
    `seller_bank_account_status` STRING COMMENT 'Overall lifecycle state of the bank account record.. Valid values are `active|inactive|suspended|pending`',
    `swift_bic` STRING COMMENT 'Bank Identifier Code used for international transfers.. Valid values are `^[A-Z]{8}([A-Z]{3})?$`',
    `tokenization_method` STRING COMMENT 'Method used to protect the account number (e.g., vault, detokenize, none).. Valid values are `vault|detokenize|none`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the bank account record.',
    `verification_status` STRING COMMENT 'Current verification state of the bank account (pending, verified, or failed).. Valid values are `pending|verified|failed`',
    `verification_status_date` TIMESTAMP COMMENT 'Date and time when the verification status was last updated.',
    CONSTRAINT pk_seller_bank_account PRIMARY KEY(`seller_bank_account_id`)
) COMMENT 'Stores verified bank account and payment disbursement method records for each seller. Captures account holder name, bank name, account type (checking/savings/business), account number (tokenized/masked per PCI DSS), routing number, IBAN, SWIFT/BIC code, currency, country, verification status (pending/verified/failed), primary payout flag, and date verified. A seller may have multiple bank accounts across currencies. Directly referenced by seller_payout for disbursement routing. PCI DSS-compliant storage with tokenization.';

